(function(){ function pkrInit(){ var QUESTIONS = [ { dim:'attachment', text:"Pas pasangan/gebetan lebih lama dari biasanya balas chat, reaksi pertamamu biasanya...", options:[ {t:"Santai aja, mungkin dia lagi sibuk", k:"secure"}, {t:"Mulai mikir macem-macem, takut ada yang salah", k:"anxious"}, {t:"Malah lega, jadi ada waktu buat diri sendiri", k:"avoidant"}, {t:"Campur — kadang santai, tiba-tiba parno sendiri", k:"disorganized"} ]}, { dim:'attachment', text:"Kalau hubungan mulai terasa makin dekat dan serius, yang biasa kamu rasain...", options:[ {t:"Nyaman, makin percaya sama orangnya", k:"secure"}, {t:"Makin nempel, takut kedekatan ini hilang", k:"anxious"}, {t:"Mulai butuh jarak, walau sulit jelasin kenapa", k:"avoidant"}, {t:"Pengen deket tapi juga was-was bakal disakitin", k:"disorganized"} ]}, { dim:'attachment', text:"Waktu ada konflik kecil sama orang deket, respons pertamamu...", options:[ {t:"Ajak ngomong baik-baik, cari solusi bareng", k:"secure"}, {t:"Takut banget dia bakal ninggalin/marah beneran", k:"anxious"}, {t:"Pengen selesein sendiri, males bahas panjang", k:"avoidant"}, {t:"Bingung sendiri, antara mau deketin atau kabur", k:"disorganized"} ]}, { dim:'attachment', text:"Soal cerita masalah atau minta bantuan ke orang lain, kamu biasanya...", options:[ {t:"Cukup terbuka kalau emang butuh", k:"secure"}, {t:"Sering cerita, kadang berlebihan takut gak didengerin", k:"anxious"}, {t:"Lebih milih pendam sendiri", k:"avoidant"}, {t:"Pengen cerita tapi takut dihakimin, jadi maju-mundur", k:"disorganized"} ]}, { dim:'attachment', text:"Dalam hubungan, yang paling bikin kamu gak nyaman adalah...", options:[ {t:"Kalau komunikasi jadi gak jujur", k:"secure"}, {t:"Kalau ngerasa gak diprioritasin", k:"anxious"}, {t:"Kalau ruang pribadi kerasa diambil", k:"avoidant"}, {t:"Kalau harus milih antara deket atau jaga jarak", k:"disorganized"} ]}, { dim:'attachment', text:"Kalau gak bisa dihubungin cukup lama (misal orang itu lagi traveling), reaksimu...", options:[ {t:"Ya udah gapapa, nanti juga cerita", k:"secure"}, {t:"Was-was, mikirin macem-macem", k:"anxious"}, {t:"Justru menikmati waktu sendiri", k:"avoidant"}, {t:"Awalnya santai, lama-lama jadi resah sendiri", k:"disorganized"} ]}, { dim:'coping', text:"Ada orang minta tolong padahal kamu lagi capek banget, biasanya kamu...", options:[ {t:"Tetap bantuin walau capek, susah nolak", k:"anakbaik"}, {t:"To the point bilang gak bisa, fokus urus diri sendiri", k:"mandiri"}, {t:"Bantu, tapi diem-diem nahan capeknya sendiri", k:"diam"}, {t:"Bantuin sambil mikir ini nambah nilai plus buat aku", k:"berprestasi"} ]}, { dim:'coping', text:"Waktu kerjaan/tugas gak sesuai target, reaksi pertamamu ke diri sendiri...", options:[ {t:"Takut orang lain kecewa duluan", k:"anakbaik"}, {t:"Langsung cari solusi sendiri tanpa cerita siapa-siapa", k:"mandiri"}, {t:"Diem, gak mau bikin orang lain ikut kepikiran", k:"diam"}, {t:"Keras ke diri sendiri, harus lebih baik lagi", k:"berprestasi"} ]}, { dim:'coping', text:"Soal cerita perasaan yang lagi berat, kamu biasanya...", options:[ {t:"Susah cerita, takut ngerepotin orang lain", k:"anakbaik"}, {t:"Mendingan dipendam, gak terbiasa cerita", k:"mandiri"}, {t:"Diem total, bahkan ke orang terdekat sekalipun", k:"diam"}, {t:"Sibukin diri kerja/aktivitas biar gak keinget", k:"berprestasi"} ]}, { dim:'coping', text:"Kalau lagi dapat pujian atau pencapaian, yang kamu rasain...", options:[ {t:"Lega, akhirnya ada yang notice usahaku", k:"anakbaik"}, {t:"Biasa aja, emang harusnya gitu", k:"mandiri"}, {t:"Agak canggung, gak terbiasa disorot", k:"diam"}, {t:"Seneng sebentar, tapi udah mikir target berikutnya", k:"berprestasi"} ]}, { dim:'coping', text:"Waktu kamu capek banget dan pengen istirahat total, biasanya...", options:[ {t:"Tetap kepikiran orang lain butuh apa dariku", k:"anakbaik"}, {t:"Istirahat sendiri, gak mau diganggu atau ngerepotin", k:"mandiri"}, {t:"Istirahat, tapi diem-diem gak bilang lagi capek", k:"diam"}, {t:"Susah istirahat kalau target belum tercapai", k:"berprestasi"} ]}, { dim:'coping', text:"Kalau disuruh milih, kamu lebih takut...", options:[ {t:"Dianggap egois atau gak baik", k:"anakbaik"}, {t:"Bergantung sama orang lain", k:"mandiri"}, {t:"Bikin orang lain gak nyaman/kesel", k:"diam"}, {t:"Dianggap gagal atau biasa-biasa aja", k:"berprestasi"} ]} ]; var ATTACHMENT_RESULT = { secure: { title: "Si Tenang yang Percaya", desc: "Kamu cenderung nyaman dengan kedekatan tanpa kehilangan rasa aman dalam dirimu sendiri. Ini bukan berarti hidupmu tanpa masalah relasi — tapi biasanya kamu punya kapasitas lebih besar untuk komunikasi jujur dan percaya tanpa harus mengontrol semuanya.", link: "https://www.psikorealis.id/2026/07/kenapa-pola-hubungan-terbentuk-sebelum-bisa-mengingat.html" }, anxious: { title: "Si Pencari Kepastian", desc: "Kedekatan terasa penting banget buat kamu, sampai jarak sedikit saja bisa memicu kecemasan. Ini bukan soal posesif — otakmu belajar dari pengalaman awal bahwa perhatian bisa hilang kapan saja, jadi selalu waspada menjaga kepastian itu.", link: "https://www.psikorealis.id/2026/07/kenapa-pola-hubungan-terbentuk-sebelum-bisa-mengingat.html" }, avoidant: { title: "Si Penjaga Jarak", desc: "Kemandirian terasa lebih aman buat kamu dibanding bergantung ke orang lain. Bukan karena gak peduli — biasanya ini kebentuk karena kedekatan dulu pernah terasa berisiko, jadi jarak jadi cara paling aman untuk melindungi diri.", link: "https://www.psikorealis.id/2026/07/kenapa-pola-hubungan-terbentuk-sebelum-bisa-mengingat.html" }, disorganized: { title: "Si Tarik-Ulur", desc: "Ada dua dorongan yang jalan bersamaan dalam dirimu: ingin dekat, sekaligus takut kalau kedekatan itu berujung terluka. Ini yang bikin kamu kadang terasa maju-mundur — bukan karena plin-plan, tapi karena dua rasa itu memang saling tarik.", link: "https://www.psikorealis.id/2026/07/kenapa-pola-hubungan-terbentuk-sebelum-bisa-mengingat.html" } }; var COPING_RESULT = { anakbaik: { title: "Anak Baik", desc: "Strategi bertahanmu terbentuk dari belajar bahwa kasih sayang datang lewat menyenangkan orang lain. Susah menolak bukan soal kurang tegas — itu alarm lama yang masih menganggap penolakan berarti kehilangan kasih sayang.", link: "https://www.psikorealis.id/2026/07/kenapa-reaksi-dijalankan-anak-kecil-di-kepala.html" }, mandiri: { title: "Si Mandiri Sejak Dini", desc: "Kamu belajar lebih awal dari kebanyakan orang bahwa mengandalkan diri sendiri lebih aman daripada berharap pada orang lain. Ini bukan soal gak butuh siapa-siapa — ini soal kekecewaan lama yang membentuk cara bertahanmu sekarang.", link: "https://www.psikorealis.id/2026/07/kenapa-reaksi-dijalankan-anak-kecil-di-kepala.html" }, diam: { title: "Si Penjaga Kedamaian", desc: "Diam adalah strategi paling aman yang kamu pelajari — karena bersuara dulu pernah terasa lebih berisiko daripada tetap tenang. Ini bukan soal gak punya pendapat, ini soal refleks bertahan dari masa lalu.", link: "https://www.psikorealis.id/2026/07/kenapa-reaksi-dijalankan-anak-kecil-di-kepala.html" }, berprestasi: { title: "Si Pengejar Prestasi", desc: "Kamu belajar bahwa perhatian dan kasih sayang datang lewat pencapaian. Dorongan untuk terus berprestasi bukan cuma soal ambisi — itu bisa jadi cara lama otakmu mencari kepastian bahwa kamu masih layak diperhatikan.", link: "https://www.psikorealis.id/2026/07/kenapa-reaksi-dijalankan-anak-kecil-di-kepala.html" } }; var COMBO = { "secure_anakbaik": "Kamu punya dasar rasa aman dalam hubungan, tapi tetap membawa kebiasaan mengutamakan orang lain dari kecil. Biasanya ini artinya kamu baik hati karena pilihan, bukan karena takut — tapi tetap perlu diperhatikan supaya gak kelelahan sendirian.", "secure_mandiri": "Rasa amanmu dalam hubungan dan kemandirianmu berjalan seiringan dengan cukup sehat. Kamu bisa dekat dengan orang lain tanpa merasa harus kehilangan diri sendiri.", "secure_diam": "Kamu cukup nyaman dalam hubungan, tapi dari kecil belajar menahan pendapat demi menjaga suasana. Ini kombinasi yang bikin kamu terlihat tenang, walau kadang perlu diingatkan untuk tetap bersuara kalau ada yang mengganjal.", "secure_berprestasi": "Kamu bisa dekat dengan orang lain secara sehat, tapi tetap punya dorongan kuat untuk terus mencapai sesuatu. Prestasi buatmu mungkin lebih soal kepuasan diri, bukan semata cari validasi.", "anxious_anakbaik": "Kecemasan akan kehilangan kedekatan bertemu dengan kebiasaan selalu menyenangkan orang lain. Kombinasi ini sering membuatmu berusaha keras menjaga hubungan tetap baik, kadang sampai mengabaikan kebutuhanmu sendiri.", "anxious_mandiri": "Ada sisi yang butuh kepastian dalam hubungan, tapi juga terbiasa menghadapi semuanya sendiri. Kombinasi ini bisa terasa melelahkan — cemas akan kehilangan, tapi juga sungkan minta didampingi.", "anxious_diam": "Kamu cemas soal kedekatan, tapi juga belajar diam demi menjaga suasana tetap aman. Ini kombinasi yang bikin kekhawatiranmu sering dipendam sendiri alih-alih dibicarakan langsung.", "anxious_berprestasi": "Kecemasan akan validasi hubungan bertemu dengan dorongan mencari validasi lewat pencapaian. Buatmu, merasa 'cukup' sering terasa seperti target yang terus bergeser, baik di hubungan maupun pekerjaan.", "avoidant_anakbaik": "Ada sisi dirimu yang menjaga jarak emosional, tapi di saat sama terbiasa menyenangkan orang lain. Kombinasi ini bisa membuatmu terlihat baik dari luar, walau di dalam tetap menjaga jarak yang cukup dalam.", "avoidant_mandiri": "Menjaga jarak dan kemandirian jalan sangat selaras dalam dirimu. Ini yang membuatmu terlihat kuat dan gak butuh siapa-siapa — walau kadang itu berarti jarang benar-benar membiarkan orang lain masuk.", "avoidant_diam": "Kamu menjaga jarak emosional sekaligus belajar diam sebagai cara bertahan. Kombinasi ini sering bikin orang lain kesulitan tahu apa yang sebenarnya kamu rasakan.", "avoidant_berprestasi": "Menjaga jarak dari kedekatan emosional, tapi mengejar pencapaian dengan gigih. Prestasi mungkin jadi ruang yang terasa lebih aman untuk dikuasai dibanding kedekatan dengan orang lain.", "disorganized_anakbaik": "Ada tarik-menarik antara ingin dekat dan takut terluka, ditambah kebiasaan selalu menyenangkan orang lain. Ini kombinasi yang cukup berat — kamu berusaha keras menjaga hubungan baik, sambil diam-diam was-was hubungan itu bisa berubah kapan saja.", "disorganized_mandiri": "Kamu ingin dekat tapi juga takut disakiti, dan cenderung menghadapi semua sendirian. Kombinasi ini bisa membuatmu jarang benar-benar meminta didampingi, walau sebenarnya butuh.", "disorganized_diam": "Dorongan ingin dekat namun takut terluka bertemu dengan kebiasaan diam demi menjaga kedamaian. Ini sering membuat pergolakan dalam dirimu jarang benar-benar tersampaikan ke orang lain.", "disorganized_berprestasi": "Tarik-ulur soal kedekatan bertemu dengan dorongan mengejar prestasi. Pencapaian mungkin jadi cara mengalihkan energi dari kebingungan soal kedekatan yang kamu rasakan." }; var ATTACHMENT_ORDER = ["secure","anxious","avoidant","disorganized"]; var COPING_ORDER = ["anakbaik","mandiri","diam","berprestasi"]; var state = { step: 0, scores: { secure:0, anxious:0, avoidant:0, disorganized:0, anakbaik:0, mandiri:0, diam:0, berprestasi:0 } }; var screenEl = document.getElementById('pkr-screen'); function safeRender(html, callback) { screenEl.classList.add('pkr-fade'); setTimeout(function(){ screenEl.innerHTML = html; screenEl.classList.remove('pkr-fade'); if(callback) callback(); }, 250); } function renderIntro(){ var html = '<span class="pkr-tag">Tes Interaktif Psikorealis</span>' + '<h1 class="pkr-seo-title">Tes Peta Pola Diri: Attachment Style & Inner Child</h1>' + '<h2 class="pkr-seo-subtitle">Kenali cara kamu terikat sama orang lain, dan strategi bertahan yang kamu bawa dari kecil.</h2>' + '<div class="pkr-meta-row">' + '<div class="pkr-meta-badge">⏱️ ±2 Menit</div>' + '<div class="pkr-meta-badge">📋 12 Pertanyaan</div>' + '<div class="pkr-meta-badge">🔒 100% Anonim</div>' + '<div class="pkr-meta-badge">🔁 Bisa Diulang Kapan Saja</div>' + '</div>' + '<p>Kuis ini menggabungkan dua hal: cara kamu terikat sama orang lain (<strong>Attachment Style</strong>) dan strategi bertahan yang kamu bawa dari kecil (<strong>Inner Child</strong>). Hasilnya bukan cuma label — tapi penjelasan kenapa kamu bereaksi seperti itu.</p>' + '<p class="pkr-small">Jawab santai sesuai kebiasaan asli kamu sehari-hari, bukan jawaban yang menurutmu "seharusnya benar" — biar hasilnya lebih akurat.</p>' + '<div style="margin-top:28px;"><button class="pkr-primary-btn" id="pkr-start">Mulai Kenali Pola Diri</button></div>'; safeRender(html, function(){ document.getElementById('pkr-start').onclick = function(){ state.step = 0; Object.keys(state.scores).forEach(function(k){ state.scores[k]=0; }); renderQuestion(); }; }); } function renderQuestion(){ var q = QUESTIONS[state.step]; var pct = Math.round((state.step / QUESTIONS.length) * 100); var dimLabel = q.dim === 'attachment' ? 'BAGIAN 1: POLA KETERIKATAN' : 'BAGIAN 2: STRATEGI BERTAHAN'; var contextText = q.dim === 'attachment' ? 'Soal cara kamu bersikap saat deket sama orang lain.' : 'Soal kebiasaan bertahan yang kamu bawa dari kecil.'; var html = '<div class="pkr-progress-container">' + '<div class="pkr-progress-track"><div class="pkr-progress-fill" style="width:'+pct+'%"></div></div>' + '<div style="display:flex; justify-content:space-between; font-size:11px; color:#808099; font-weight:600;">' + '<span>' + dimLabel + '</span><span>' + (state.step+1) + '/' + QUESTIONS.length + '</span>' + '</div></div>' + '<div class="pkr-context-label">' + contextText + '</div>' + '<h3>' + q.text + '</h3>'; q.options.forEach(function(opt){ html += '<button class="pkr-btn" data-k="' + opt.k + '">' + opt.t + '</button>'; }); safeRender(html, function(){ var btns = screenEl.querySelectorAll('.pkr-btn'); btns.forEach(function(b){ b.onclick = function(){ state.scores[this.getAttribute('data-k')]++; state.step++; if(state.step < QUESTIONS.length){ renderQuestion(); } else { renderLoading(); } }; }); }); } function renderLoading(){ var html = '<div class="pkr-loader-container">' + '<div class="pkr-spinner"></div>' + '<div id="pkr-loader-text">Menyusun hasilmu...</div>' + '</div>'; safeRender(html, function(){ var messages = [ "Mencocokkan pola keterikatanmu...", "Mencocokkan strategi bertahanmu...", "Menyusun Peta Pola Dirimu..." ]; var i = 0; var interval = setInterval(function(){ if(i < messages.length){ document.getElementById('pkr-loader-text').innerText = messages[i]; i++; } else { clearInterval(interval); renderResult(); } }, 900); }); } function getTiedKeys(order){ var max = -1; order.forEach(function(k){ if(state.scores[k] > max) max = state.scores[k]; }); return order.filter(function(k){ return state.scores[k] === max; }); } function buildDimensionResult(tiedKeys, RESULT_MAP){ if(tiedKeys.length === 1){ var r = RESULT_MAP[tiedKeys[0]]; return { title: r.title, desc: r.desc, link: r.link }; } if(tiedKeys.length === 2){ var r1 = RESULT_MAP[tiedKeys[0]], r2 = RESULT_MAP[tiedKeys[1]]; var desc2lower = r2.desc.charAt(0).toLowerCase() + r2.desc.slice(1); return { title: r1.title + " & " + r2.title + " (Berimbang)", desc: "Jawabanmu berimbang antara dua pola ini — kemungkinan besar kamu menunjukkan keduanya tergantung situasi. " + r1.desc + " Di sisi lain, " + desc2lower, link: r1.link }; } var titles = tiedKeys.map(function(k){ return RESULT_MAP[k].title; }).join(", "); return { title: "Pola yang Masih Cair", desc: "Jawabanmu tersebar cukup merata di beberapa pola sekaligus (" + titles + "). Coba ulangi tes ini sambil membayangkan satu hubungan tertentu.", link: RESULT_MAP[tiedKeys[0]].link }; } function renderResult(){ var attKeys = getTiedKeys(ATTACHMENT_ORDER); var copKeys = getTiedKeys(COPING_ORDER); var att = buildDimensionResult(attKeys, ATTACHMENT_RESULT); var cop = buildDimensionResult(copKeys, COPING_RESULT); var combo = (attKeys.length === 1 && copKeys.length === 1) ? COMBO[attKeys[0] + "_" + copKeys[0]] : "Hasilmu berada di persimpangan beberapa pola sekaligus."; if (typeof gtag === "function") { gtag("event", "hasil_tes", { nama_tool: "peta_pola_diri", kombinasi: att.title + " x " + cop.title }); } try { localStorage.setItem("pkr_result_peta_pola_diri", JSON.stringify({ type: att.title, context: cop.title, date: new Date().toISOString() })); } catch (e) {} var currentUrl = window.location.href; var shareText = "Barusan nyoba Peta Pola Diri di Psikorealis. Hasilku: Pola " + att.title + " & Strategi " + cop.title + ". Akurat banget buat refleksi diri. Coba tes punyamu disini: " + currentUrl; var twitterUrl = "https://twitter.com/intent/tweet?text=" + encodeURIComponent(shareText); var telegramUrl = "https://t.me/share/url?url=" + encodeURIComponent(currentUrl) + "&text=" + encodeURIComponent("Hasil Peta Pola Diriku: " + att.title + " & " + cop.title + ". Cek punyamu juga!"); var threadsUrl = "https://www.threads.net/intent/post?text=" + encodeURIComponent(shareText); var whatsappUrl = "https://api.whatsapp.com/send?text=" + encodeURIComponent(shareText); var html = '<div id="pkr-print-area">' + '<span class="pkr-tag">Hasil Peta Pola Dirimu</span>' + '<h2>Hasil Peta Pola Dirimu</h2>' + '<p class="pkr-small" style="margin-bottom:24px;">Hasil dari psikorealis.id — bukan diagnosis, cuma cara mengenali pola.</p>' + '<div class="pkr-card"><h4>Dimensi 1: ' + att.title + '</h4><p>' + att.desc + '</p></div>' + '<div class="pkr-card"><h4>Dimensi 2: ' + cop.title + '</h4><p>' + cop.desc + '</p></div>' + '<h3 style="margin-top:24px; font-size:16px;">Titik Temu Keduanya</h3><p style="font-size:14px; color:#CCCCCC;">' + combo + '</p>' + '<hr class="pkr-divider">' + '<h3>Buat Direnungkan (Bukan Diselesaikan Hari Ini)</h3>' + '<div class="pkr-reflect">1. Kapan terakhir kali pola proteksi ini muncul dalam interaksi sosial harianmu? Bagaimana rasanya?</div>' + '<div class="pkr-reflect">2. Jika pola otomatis ini berhasil diredam, tindakan alternatif apa yang lebih sehat untuk kamu ambil?</div>' + '<hr class="pkr-divider">' + '<p class="pkr-small">Baca lebih dalam:</p>' + '<p class="pkr-small" style="margin-bottom:6px;">→ <a href="' + att.link + '" target="_blank">Kenapa Pola Hubunganmu Terbentuk Sebelum Kamu Bisa Mengingat?</a></p>' + '<p class="pkr-small">→ <a href="' + cop.link + '" target="_blank">Kenapa Reaksimu Hari Ini Masih Dijalankan oleh Anak Kecil?</a></p>' + '</div>' + '<div class="pkr-share-box pkr-no-print">' + '<div class="pkr-share-title">Bagikan Laporan Refleksi Ini</div>' + '<div class="pkr-share-grid">' + '<button class="pkr-share-btn pkr-share-link-btn pkr-share-btn-full" id="pkr-copy-link"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:-2px;margin-right:6px;"><path d="M10 13a5 5 0 007.07 0l2.83-2.83a5 5 0 00-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 00-7.07 0l-2.83 2.83a5 5 0 007.07 7.07l1.71-1.71"/></svg>Salin Teks & Link Kuis</button>' + '<a href="' + whatsappUrl + '" target="_blank" class="pkr-share-btn pkr-share-btn-wa"><svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor" style="vertical-align:-2px;margin-right:6px;"><path d="M12 2C6.48 2 2 6.48 2 12c0 1.85.5 3.58 1.38 5.07L2 22l5.07-1.33A9.94 9.94 0 0012 22c5.52 0 10-4.48 10-10S17.52 2 12 2z"/></svg>WhatsApp</a>' + '<a href="' + telegramUrl + '" target="_blank" class="pkr-share-btn"><svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor" style="vertical-align:-2px;margin-right:6px;"><path d="M21.5 2.5L2 10.5l6 2.3L19 5l-9 8.5.4 6 3-3.2 5 3.7 3-17z"/></svg>Telegram</a>' + '<a href="' + threadsUrl + '" target="_blank" class="pkr-share-btn"><span style="font-weight:800;margin-right:6px;">@</span>Threads</a>' + '<a href="' + twitterUrl + '" target="_blank" class="pkr-share-btn"><span style="font-weight:800;margin-right:6px;">X</span>Twitter</a>' + '</div>' + '</div>' + '<div class="pkr-no-print" style="margin-top:24px; text-align:center;">' + '<button class="pkr-primary-btn" id="pkr-print">Simpan Dokumen (PDF)</button>' + '<button class="pkr-ghost-btn" id="pkr-retake" style="margin-left:8px;">Ulangi Tes</button>' + '</div>'; safeRender(html, function(){ document.getElementById('pkr-retake').onclick = renderIntro; document.getElementById('pkr-print').onclick = function(){ window.print(); }; document.getElementById('pkr-copy-link').onclick = function(){ navigator.clipboard.writeText(shareText).then(function() { var btn = document.getElementById('pkr-copy-link'); var oldTxt = btn.innerText; btn.innerText = "✅ Berhasil Tersalin!"; setTimeout(function(){ btn.innerText = oldTxt; }, 2000); }); }; }); } renderIntro(); } function pkrStart(){ if(document.getElementById('pkr-app')){ pkrInit(); } else { setTimeout(pkrStart, 200); } } if(document.readyState === 'loading'){ document.addEventListener('DOMContentLoaded', pkrStart); } else { pkrStart(); } })();